SELECT [Sales Header].[Sell-to Customer No_], [CommentiOrdiniDiVendita-step0].Name, [Sales Header].[Ship-to City], IIf([Order Type]=1,"Riass.",IIf([order type]=2,"Pronto",IIf([order type]=3,"Stock",IIf([order type]=4,"Sost.",IIf([order type]=0,"Progr","?"))))) AS OrderType, [CommentiOrdiniDiVendita-step0].[Document No_], [CommentiOrdiniDiVendita-step0].[Season Code], [CommentiOrdiniDiVendita-step0].[Trademark Code], [CommentiOrdiniDiVendita-step1].Date, [CommentiOrdiniDiVendita-step1].Code, [CommentiOrdiniDiVendita-step1].Comment, [Sales Header].[Shipment Method Code] AS ShipmentMethodCode, [Shipment Method].Description AS ShipmentMethodDescription, [Sales Header.Payment Method Code] AS OrderPaymentMethod, [Sales Header.Payment Terms Code] AS OrderPaymentTerm, [Customer.Payment Method Code] AS CustomerPaymentMethod, [Customer.Payment Terms Code] AS CustomerPaymentTerm, [Sales Header].[Area Manager Code], Salesperson_Purchaser_1.Name AS AreaManagerName, [CommentiOrdiniDiVendita-step0].AreaManagerCommission, [Sales Header].[Salesperson Code], Salesperson_Purchaser.Name AS SalsePersonName, [CommentiOrdiniDiVendita-step0].SalesPersonCommission, [Sales Header].[Requested Delivery Date], Val([Invoice Discount Value]) AS InvoiceDiscount, Val([Right on Return _]) AS DirittoAlReso, [Sales Header].Consignment AS PercentualeReso, Customer.[Current Risk] AS LinceRischioOggi, [Sales Header].Note, Val([Line Discount _]) AS ScontoRiga, [CommentiOrdiniDiVendita-step0].ValueSold, [CommentiOrdiniDiVendita-step0].PairsSold, [Sales Header].[Geographical Zone] AS OrderGeographicalZone, [Geographical Zone].Description AS OrderGeographicalZoneDescription, Customer.[Geographical Zone] AS CustomerGeographicalZone, [Geographical Zone_1].Description AS CustomerGeographicalZoneDescription, Customer.[Geographical Zone 2] AS CustomerGeographicalZone2, [Geographical Zone_2].Description AS CustomerGeographicalZone2Description, IIf([Consignment]=True,"SI","NO") AS ContoVendita, [Sales Header].[Course Date] AS DataDecorrenza
FROM (((((((([CommentiOrdiniDiVendita-step0] LEFT JOIN [CommentiOrdiniDiVendita-step1] ON ([CommentiOrdiniDiVendita-step0].[Document Type] = [CommentiOrdiniDiVendita-step1].[Document Type]) AND ([CommentiOrdiniDiVendita-step0].[Document No_] = [CommentiOrdiniDiVendita-step1].No_)) LEFT JOIN [Sales Header] ON ([CommentiOrdiniDiVendita-step0].[Document Type] = [Sales Header].[Document Type]) AND ([CommentiOrdiniDiVendita-step0].[Document No_] = [Sales Header].No_)) LEFT JOIN Salesperson_Purchaser ON [Sales Header].[Salesperson Code] = Salesperson_Purchaser.Code) LEFT JOIN Customer ON [Sales Header].[Bill-to Customer No_] = Customer.No_) LEFT JOIN [Geographical Zone] ON [Sales Header].[Geographical Zone] = [Geographical Zone].[Code]) LEFT JOIN [Geographical Zone] AS [Geographical Zone_1] ON Customer.[Geographical Zone] = [Geographical Zone_1].[Code]) LEFT JOIN [Geographical Zone] AS [Geographical Zone_2] ON Customer.[Geographical Zone 2] = [Geographical Zone_2].[Code]) LEFT JOIN [Shipment Method] ON [Sales Header].[Shipment Method Code] = [Shipment Method].Code) LEFT JOIN Salesperson_Purchaser AS Salesperson_Purchaser_1 ON [Sales Header].[Area Manager Code] = Salesperson_Purchaser_1.Code
WHERE ((([CommentiOrdiniDiVendita-step0].[Season Code])=[forms]![principale]![FiltroStagioneEAN]))
ORDER BY [CommentiOrdiniDiVendita-step0].[Document No_];

